Lemma Omega_diverges : forall v, ~ eval Omega v.
Proof.
  intros v H.
  remember Omega as t.
  induction H; try (subst; discriminate).
  subst. unfold Omega. cbn. eauto.
Qed.

Lemma eval_value : forall t v, eval t v -> value v.
Proof.
  induction 1; eauto using value.
  constructor; eauto.
Qed.

Lemma eval_det : forall t v1 v2, eval t v1 -> eval t v2 -> v1 = v2.
Proof.
  induction t; intros v1 v2 H1 H2;
    inversion H1; inversion H2; subst; try reflexivity; eauto;
    try (apply IHt1 in H4; [|exact H5]); try inversion H4;
    try (apply IHt2 in H7; [|exact H6]); subst;
    try (apply IHt3 in H2; [|exact H8]); eauto;
    try (apply IHt in H0; [|exact H3]); subst; auto;
    try (apply IHt in H0; [|exact H3]); inversion H0;
    try (apply IHt1 in H7; [|exact H0]); inversion H7; subst; [apply IHt2|apply IHt3]; eauto;
    try (apply IHt1 in H7; [|exact H0]); inversion H7.
Qed.

