Proof.
  intros t v1 v2 H1. revert v2.
  induction H1; intros vs H2; inversion H2; subst;
    try reflexivity;
    try (f_equal; eapply IHeval; eassumption);
    try (eapply IHeval; eassumption);
    try (eapply IHeval2; eassumption);
    try (eapply IHeval3; eassumption);
    try (apply IHeval1 in H4; inversion H4; subst; clear H4;
         apply IHeval2 in H8; subst; clear H8;
         eapply IHeval3; eassumption);
    try (apply IHeval1 in H0; inversion H0; subst; eapply IHeval2; eassumption);
    try (apply IHeval1 in H0; inversion H0; subst; eapply IHeval2; eassumption);
    try (apply IHeval in H0; inversion H0);
    try (apply IHeval in H0; inversion H0; subst);
    try (exfalso; solve [inversion H | inversion H0]);
    try (exfalso; discriminate).
Qed.

